=PROGRAMME : {{ $('Parse Architecte JSON').item.json.title }}
PUBLIC : {{ $('Parse Architecte JSON').item.json.target_audience }}

UNITÉ À RÉDIGER :
- Titre : {{ $json.title }}
- Résumé : {{ $json.summary }}
- Durée totale : {{ $json.duration_minutes }} min
- Steps prévus : {{ JSON.stringify($json.steps) }}

CONTENU SOURCE (pour t'inspirer) :
"""
{{ $('Extract from File').item.json.text }}
"""

TÂCHE :
Rédige le contenu COMPLET de chaque step. Pour chaque step, fournis un array de blocs Notion utilisables directement par l'API Notion.

TYPES DE BLOCS AUTORISÉS :
- heading_2 (titres principaux)
- heading_3 (sous-titres)
- paragraph (corps de texte, courts)
- bulleted_list_item (listes)
- numbered_list_item (étapes numérotées, exercices)
- callout (avec emoji 💡 pour conseil, ⚠️ pour attention, 🎯 pour objectif, 📌 pour point clé)
- quote (citation, anecdote)
- code (commandes, prompts à utiliser)

LIVRE EXACTEMENT CE JSON (rien d'autre, pas de wrapper markdown) :
{
  "steps": [
    {
      "order": 1,
      "title": "...",
      "type": "intro"|"step"|"conclusion"|"option",
      "duration_minutes": 10,
      "blocks": [
        { "type": "heading_2", "text": "..." },
        { "type": "paragraph", "text": "..." },
        { "type": "callout", "icon": "💡", "text": "..." }
      ]
    }
  ]
}

CONTRAINTES :
- 5 à 15 blocs par step
- Toujours commencer par heading_2 ou callout
- Pour exercices : numbered_list_item avec verbe d'action en début
- Pas de blabla "Dans cette section..." — direct au but

parameters.jsCode:
// Parse la réponse Claude + transforme en blocks API Notion + prepare la unit
const raw = $input.first().json.text || $input.first().json.output || '';
const cleaned = String(raw).replace(/^```json\n?|```$/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Rédacteur: JSON invalide. ' + e.message + '\n\nReçu:\n' + raw);
}

// Convertit le format simplifié de Claude en format API Notion
function toNotionBlock(b) {
  const richText = (text) => [{ type: 'text', text: { content: String(text || '') } }];
  switch (b.type) {
    case 'heading_2':
      return { object: 'block', type: 'heading_2', heading_2: { rich_text: richText(b.text) } };
    case 'heading_3':
      return { object: 'block', type: 'heading_3', heading_3: { rich_text: richText(b.text) } };
    case 'paragraph':
      return { object: 'block', type: 'paragraph', paragraph: { rich_text: richText(b.text) } };
    case 'bulleted_list_item':
      return { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: richText(b.text) } };
    case 'numbered_list_item':
      return { object: 'block', type: 'numbered_list_item', numbered_list_item: { rich_text: richText(b.text) } };
    case 'callout':
      return {
        object: 'block', type: 'callout',
        callout: {
          icon: { type: 'emoji', emoji: b.icon || '💡' },
          rich_text: richText(b.text)
        }
      };
    case 'quote':
      return { object: 'block', type: 'quote', quote: { rich_text: richText(b.text) } };
    case 'code':
      return { object: 'block', type: 'code', code: { rich_text: richText(b.text), language: 'plain text' } };
    case 'divider':
      return { object: 'block', type: 'divider', divider: {} };
    default:
      return { object: 'block', type: 'paragraph', paragraph: { rich_text: richText(b.text || '') } };
  }
}

const unitData = $('Split Units').item.json;
const stepsForOutput = (parsed.steps || []).map((step) => {
  // Callout ⚙️ Config en haut du step
  const configCallout = {
    object: 'block',
    type: 'callout',
    callout: {
      icon: { type: 'emoji', emoji: '⚙️' },
      rich_text: [{ type: 'text', text: { content: 'Config' } }]
    }
  };
  // Bullets de config — placés APRÈS le callout (Notion les attache visuellement)
  const stepTypeFr = step.type === 'step' ? 'étape' : step.type;
  const configBullets = [
    { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: `Type : ${stepTypeFr}` } }] } },
    { object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: [{ type: 'text', text: { content: `Durée : ${step.duration_minutes} min` } }] } }
  ];
  const contentBlocks = (step.blocks || []).map(toNotionBlock);
  return {
    title: step.title,
    blocks: [configCallout, ...configBullets, ...contentBlocks]
  };
});

return [{
  json: {
    unit_title: unitData.title,
    unit_summary: unitData.summary,
    unit_duration_minutes: unitData.duration_minutes,
    unit_unlock_offset_days: unitData.unlock_offset_days,
    steps: stepsForOutput,
    program_page_id: $('Notion — Create Program Page').item.json.id
  }
}];

// Pour chaque step de la unit, prépare une requête de création de sub-child page
const data = $('Transform Blocks').item.json;
const unitPageId = $('Notion — Create Unit Page').item.json.id;

const stepRequests = data.steps.map((step) => ({
  unit_page_id: unitPageId,
  step_title: step.title,
  step_blocks: step.blocks
}));

return stepRequests.map((s) => ({ json: s }));

